import type { RepoLogger } from '@motivation/shared';

/**
 * Component-scoped logger for the PWA.
 *
 * Produces log calls that flow through the patched `console.*` methods
 * (installed by `installConsoleCapture`), but tag each entry with the
 * component's name as the `module` field instead of the hardcoded `'client'`.
 *
 * Usage:
 *   private readonly log = createComponentLogger('health-dashboard-screen');
 *   this.log.error('loadData failed:', err);
 */

export interface ComponentLogger {
    info(...args: unknown[]): void;
    warn(...args: unknown[]): void;
    error(...args: unknown[]): void;
    debug(...args: unknown[]): void;
}

/**
 * Shared symbol used as a marker key on the first argument of a tagged
 * console call. `buildEntryFromArgs` in `client-log-buffer.ts` detects
 * this marker and extracts the module name.
 */
export const MODULE_TAG = Symbol.for('motivation:log-module');

export function createComponentLogger(name: string): ComponentLogger {
    const tag = (args: unknown[]): unknown[] => {
        const marker = { [MODULE_TAG]: name };
        return [marker, ...args];
    };
    return {
        info:  (...args: unknown[]) => console.info(...tag(args)),
        warn:  (...args: unknown[]) => console.warn(...tag(args)),
        error: (...args: unknown[]) => console.error(...tag(args)),
        debug: (...args: unknown[]) => console.debug(...tag(args)),
    };
}

/**
 * Adapter from the PWA's tagged `console.*` pipeline to the shared
 * `RepoLogger` shape (story 150). Shared repositories accept `RepoLogger` so
 * either runtime can inject its own logger; on the PWA we route through the
 * client-log-buffer so repo events land in the same log stream as component
 * logs and ship via Background Sync.
 */
export function createRepoLogger(name: string): RepoLogger {
    const c = createComponentLogger(name);
    return {
        debug: (message, context) => c.debug(message, context),
        info:  (message, context) => c.info(message, context),
        warn:  (message, context) => c.warn(message, context),
        error: (message, context) => c.error(message, context),
    };
}

/**
 * Extract a module name from the args array if the first element carries
 * the MODULE_TAG marker. Returns the module name and the cleaned args
 * (marker removed). Falls back to the provided default.
 */
export function extractModule(args: unknown[], fallback: string): { module: string; cleanArgs: unknown[] } {
    if (
        args.length > 0 &&
        typeof args[0] === 'object' &&
        args[0] !== null &&
        MODULE_TAG in args[0]
    ) {
        return {
            module: (args[0] as Record<symbol, string>)[MODULE_TAG],
            cleanArgs: args.slice(1),
        };
    }
    return { module: fallback, cleanArgs: args };
}
